  }
  #files-listing {
    flex: 1;
    overflow-y: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(84px, 1fr));
    gap: 10px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    padding: 8px 4px;
    border-radius: 8px;
    cursor: pointer;
    font-size: 12px;
    text-align: center;
    word-break: break-word;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(233, 84, 32, 0.35); }
  .fs-item .fs-glyph { font-size: 26px; }

  /* ---------- Notepad app ---------- */
  #notepad-window { top: 130px; left: 260px; }
  #tabs {
    display: flex;
    align-items: center;
    background: #2a2135;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    flex: 0 0 auto;
    overflow-x: auto;
  }
  .tab {
    padding: 8px 12px;
    font-size: 12px;
    color: #cfc7da;
    cursor: pointer;
    border-right: 1px solid rgba(255,255,255,0.06);
    display: flex;
    align-items: center;
