  .tab.active { background: #241c2e; color: #fff; border-top: 2px solid #e95420; }
  .tab .tab-close {
    border: none;
    background: transparent;
    color: #cfc7da;
    cursor: pointer;
    font-size: 12px;
    line-height: 1;
    padding: 0 2px;
    border-radius: 3px;
  }
  .tab .tab-close:hover { background: rgba(255,255,255,0.15); }
  #new-tab {
    border: none;
    background: transparent;
    color: #cfc7da;
    font-size: 16px;
    cursor: pointer;
