<body>

<div id="desktop">
  <div id="topbar">Ubuntu Desktop &mdash; Activities</div>

  <div id="desktop-icons">
    <div class="desktop-icon" data-open="files-window">
      <div class="glyph">🗂️</div>
      <span class="label">Files</span>
    </div>
    <div class="desktop-icon" data-open="notepad-window">
      <div class="glyph">📝</div>
      <span class="label">Notepad</span>
    </div>
  </div>

  <!-- Files window -->
  <div id="files-window" class="app-window">
    <div class="win-titlebar" data-win="files-window">
      <div class="win-title">🗂️ Files</div>
      <div class="win-controls">
        <button class="win-btn win-min" title="Minimize"></button>
        <button class="win-btn win-max" title="Maximize"></button>
        <button class="win-btn win-close" title="Close"></button>
      </div>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up">&#8593; Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-listing"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div id="notepad-window" class="app-window">
    <div class="win-titlebar" data-win="notepad-window">
      <div class="win-title">📝 Notepad</div>
      <div class="win-controls">
        <button class="win-btn win-min" title="Minimize"></button>
        <button class="win-btn win-max" title="Maximize"></button>
        <button class="win-btn win-close" title="Close"></button>
      </div>
    </div>
    <div class="win-body">
      <div id="tabs">
        <button id="new-tab" title="New tab">+</button>
      </div>
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>

  <div id="taskbar">
    <button id="open-files" class="dock-btn" title="Files">🗂️</button>
    <button id="open-notepad" class="dock-btn" title="Notepad">📝</button>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ===================== Window management ===================== */

  function openWindow(id) {
    var win = document.getElementById(id);
    win.classList.add("open");
    bringToFront(win);
  }
  function closeWindow(win) {
    win.classList.remove("open");
  }

  var zTop = 100;
  function bringToFront(win) {
    zTop += 1;
    win.style.zIndex = zTop;
  }

  document.querySelectorAll(".app-window").forEach(function (win) {
    win.addEventListener("mousedown", function () { bringToFront(win); });
    win.querySelector(".win-close").addEventListener("click", function (e) {
      e.stopPropagation();
      closeWindow(win);
    });
    // Minimize just hides it too (kept simple/functional).
    win.querySelector(".win-min").addEventListener("click", function (e) {
      e.stopPropagation();
      closeWindow(win);
    });
    // Maximize toggles a full-size layout.
    var maximized = false;
    var prevRect = null;
    win.querySelector(".win-max").addEventListener("click", function (e) {
      e.stopPropagation();
      if (!maximized) {
        prevRect = {
          top: win.style.top, left: win.style.left,
          width: win.style.width, height: win.style.height
        };
        win.style.top = "32px";
        win.style.left = "2vw";
        win.style.width = "96vw";
        win.style.height = "calc(100vh - 110px)";
        maximized = true;
      } else if (prevRect) {
        win.style.top = prevRect.top;
        win.style.left = prevRect.left;
        win.style.width = prevRect.width;
        win.style.height = prevRect.height;
        maximized = false;
      }
    });
  });

  document.getElementById("open-files").addEventListener("click", function () {
    openWindow("files-window");
  });
  document.getElementById("open-notepad").addEventListener("click", function () {
    openWindow("notepad-window");
  });
  document.querySelectorAll(".desktop-icon").forEach(function (icon) {
    icon.addEventListener("dblclick", function () {
      openWindow(icon.getAttribute("data-open"));
    });
  });

  /* ---- Dragging ---- */
  document.querySelectorAll(".win-titlebar").forEach(function (bar) {
    var win = bar.closest(".app-window");
    var dragging = false, startX, startY, startLeft, startTop;

    bar.addEventListener("mousedown", function (e) {
      if (e.target.classList.contains("win-btn")) return;
      dragging = true;
      var rect = win.getBoundingClientRect();
      var deskRect = document.getElementById("desktop").getBoundingClientRect();
      startX = e.clientX;
      startY = e.clientY;
      startLeft = rect.left - deskRect.left;
      startTop = rect.top - deskRect.top;
      win.style.left = startLeft + "px";
      win.style.top = startTop + "px";
      document.addEventListener("mousemove", onMove);
      document.addEventListener("mouseup", onUp);
    });

    function onMove(e) {
      if (!dragging) return;
      var dx = e.clientX - startX;
      var dy = e.clientY - startY;
      var newLeft = Math.max(0, startLeft + dx);
      var newTop = Math.max(0, startTop + dy);
      win.style.left = newLeft + "px";
      win.style.top = newTop + "px";
    }
    function onUp() {
      dragging = false;
      document.removeEventListener("mousemove", onMove);
      document.removeEventListener("mouseup", onUp);
    }
  });

  /* ===================== Files app ===================== */

  var fsRoot = {
    type: "dir",
    children: {
      "bin": { type: "dir", children: {
        "bash": { type: "file", content: "#!ELF binary (bash)" },
        "ls": { type: "file", content: "#!ELF binary (ls)" }
      }},
      "etc": { type: "dir", children: {
        "hostname": { type: "file", content: "ubuntu-desktop" },
        "hosts": { type: "file", content: "127.0.0.1 localhost" },
        "passwd": { type: "file", content: "root:x:0:0:root:/root:/bin/bash\nuser:x:1000:1000:user:/home/user:/bin/bash" }
      }},
      "home": { type: "dir", children: {
        "user": { type: "dir", children: {
          "Documents": { type: "dir", children: {
            "notes.txt": { type: "file", content: "Meeting notes go here." },
            "resume.odt": { type: "file", content: "(binary document)" }
          }},
          "Downloads": { type: "dir", children: {
            "installer.deb": { type: "file", content: "(binary package)" }
          }},
          "Pictures": { type: "dir", children: {
            "wallpaper.png": { type: "file", content: "(binary image)" },
            "screenshot.png": { type: "file", content: "(binary image)" }
          }},
          ".bashrc": { type: "file", content: "# ~/.bashrc\nexport PS1='\\u@\\h:\\w\\$ '" }
        }}
      }},
      "usr": { type: "dir", children: {
        "bin": { type: "dir", children: {
          "python3": { type: "file", content: "#!ELF binary (python3)" }
        }},
        "share": { type: "dir", children: {
          "applications": { type: "dir", children: {} }
        }}
      }},
      "var": { type: "dir", children: {
        "log": { type: "dir", children: {
          "syslog": { type: "file", content: "Jul 20 09:00:00 ubuntu systemd[1]: Started Session." }
        }},
        "www": { type: "dir", children: {} }
      }}
    }
  };

  var currentPath = []; // array of path segments from root

  function resolvePath(pathArr) {
    var node = fsRoot;
    for (var i = 0; i < pathArr.length; i++) {
      if (!node.children || !node.children[pathArr[i]]) return null;
      node = node.children[pathArr[i]];
    }
    return node;
  }

  function renderFiles() {
    var pathStr = "/" + currentPath.join("/");
    document.getElementById("files-path").textContent = pathStr;

    var listing = document.getElementById("files-listing");
    listing.innerHTML = "";

    var node = resolvePath(currentPath);
    if (!node || node.type !== "dir") return;

    var names = Object.keys(node.children).sort(function (a, b) {
      var na = node.children[a], nb = node.children[b];
      if (na.type !== nb.type) return na.type === "dir" ? -1 : 1;
      return a.localeCompare(b);
    });

    names.forEach(function (name) {
      var child = node.children[name];
      var item = document.createElement("div");
      item.className = "fs-item";
      item.setAttribute("data-name", name);

      var glyph = document.createElement("div");
      glyph.className = "fs-glyph";
      glyph.textContent = child.type === "dir" ? "📁" : "📄";

      var label = document.createElement("div");
      label.className = "fs-label";
      label.textContent = name;

      item.appendChild(glyph);
      item.appendChild(label);

      item.addEventListener("click", function () {
        listing.querySelectorAll(".fs-item").forEach(function (el) {
          el.classList.remove("selected");
        });
        item.classList.add("selected");
      });

      item.addEventListener("dblclick", function () {
        if (child.type === "dir") {
          currentPath.push(name);
          renderFiles();
        }
      });

      listing.appendChild(item);
    });
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath.length > 0) {
      currentPath.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ===================== Notepad app ===================== */

  var STORAGE_KEY = "ubuntu-desktop-notepad-tabs";
  var tabs = [];        // [{ id, name, content }]
  var activeTabId = null;
  var tabCounter = 0;

  function loadTabs() {
    var raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      try {
        var data = JSON.parse(raw);
        if (data && Array.isArray(data.tabs) && data.tabs.length > 0) {
          tabs = data.tabs;
          activeTabId = data.activeTabId != null ? data.activeTabId : tabs[0].id;
          tabCounter = data.tabCounter || tabs.length;
          return;
        }
      } catch (e) { /* fall through to defaults */ }
    }
    // defaults
    tabCounter = 1;
    tabs = [{ id: 0, name: "untitled.txt", content: "" }];
    activeTabId = 0;
  }

  function saveTabs() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({
      tabs: tabs,
      activeTabId: activeTabId,
      tabCounter: tabCounter
    }));
  }

  function getActiveTab() {
    for (var i = 0; i < tabs.length; i++) {
      if (tabs[i].id === activeTabId) return tabs[i];
    }
    return null;
  }

  function renderTabs() {
    var tabsEl = document.getElementById("tabs");
    // remove existing .tab elements, keep #new-tab
    tabsEl.querySelectorAll(".tab").forEach(function (el) { el.remove(); });
    var newTabBtn = document.getElementById("new-tab");

    tabs.forEach(function (tab) {
      var tabEl = document.createElement("div");
      tabEl.className = "tab" + (tab.id === activeTabId ? " active" : "");
      tabEl.setAttribute("data-id", tab.id);

      var nameEl = document.createElement("span");
      nameEl.className = "tab-name";
      nameEl.textContent = tab.name;

      var closeBtn = document.createElement("button");
      closeBtn.className = "tab-close";
      closeBtn.textContent = "\u2715";
      closeBtn.title = "Close tab";

      closeBtn.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(tab.id);
      });

      tabEl.addEventListener("click", function () {
        activeTabId = tab.id;
        renderTabs();
        renderEditor();
        saveTabs();
      });

      tabEl.appendChild(nameEl);
      tabEl.appendChild(closeBtn);
      tabsEl.insertBefore(tabEl, newTabBtn);
    });
  }

  function renderEditor() {
    var editor = document.getElementById("editor");
    var active = getActiveTab();
    editor.value = active ? active.content : "";
    editor.disabled = !active;
  }

  function closeTab(id) {
    var idx = tabs.findIndex(function (t) { return t.id === id; });
    if (idx === -1) return;
    tabs.splice(idx, 1);

    if (tabs.length === 0) {
      // Always keep at least one tab available.
      tabCounter += 1;
      var fresh = { id: tabCounter, name: "untitled.txt", content: "" };
      tabs.push(fresh);
      activeTabId = fresh.id;
    } else if (activeTabId === id) {
      var newIdx = Math.max(0, idx - 1);
      activeTabId = tabs[newIdx].id;
    }
    renderTabs();
    renderEditor();
    saveTabs();
  }

  document.getElementById("new-tab").addEventListener("click", function () {
    tabCounter += 1;
    var tab = { id: tabCounter, name: "untitled.txt", content: "" };
    tabs.push(tab);
    activeTabId = tab.id;
    renderTabs();
    renderEditor();
    saveTabs();
  });

  document.getElementById("editor").addEventListener("input", function (e) {
    var active = getActiveTab();
    if (!active) return;
    active.content = e.target.value;
    // Derive a display name from the first line of content, fallback to untitled.
    var firstLine = active.content.split("\n")[0].trim();
    active.name = firstLine ? firstLine.slice(0, 24) : "untitled.txt";
    renderTabs();
    saveTabs();
  });

  loadTabs();
  renderTabs();
  renderEditor();

})();
</script>
</body>
</html>
